// ─── GP Pathfinder Training — Scenario Library ───────────────────────────────
// 100+ scenarios: Receptionist (8 original + 12 new = 20) + Clinician (80+)
// Clinician scenarios cover: Acute, Chronic, CVRM multimorbidity, MRCGP/CSA-style
// All grounded in NICE/SIGN/BTS/RCGP guidelines

export type ScenarioMode = "receptionist" | "clinician";
export type Difficulty = "beginner" | "intermediate" | "advanced";

export interface ScenarioSeed {
  title: string;
  category: string;
  difficulty: Difficulty;
  mode: ScenarioMode;
  description: string;
  patientPersona: string;
  learningObjectives: string[];
  tags: string[];
  estimatedMinutes: number;
  clinicalSystem?: string;
  complexityTier?: "simple" | "medium" | "complex";
  comorbidities?: string[];
  hiddenCues?: string[];
  iceElements?: {
    ideas?: string;
    concerns?: string;
    expectations?: string;
  };
}

